#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>
#define N 200001
#define INF 1000000000000000000LL
typedef struct { int vertex; long long distance; } Node;
typedef struct { Node *nodes; int size; } MinHeap;
int compare(const void *a, const void *b) {
    Node *nodeA = (Node *)a;
    Node *nodeB = (Node *)b;
    return nodeA->distance > nodeB->distance;
}
void dijkstra(int N, int M, int **edges) {
    long long *distances = (long long *)calloc(N, sizeof(long long));
    for (int i = 0; i < N; i++) {
        distances[i] = INF;
    }
    distances[0] = 0;
    MinHeap minHeap;
    minHeap.nodes = (Node *)calloc(N, sizeof(Node));
    minHeap.size = 0;
    for (int i = 0; i < N; i++) {
        minHeap.nodes[i].vertex = i;
        minHeap.nodes[i].distance = distances[i];
        minHeap.size++;
    }
    qsort(minHeap.nodes, minHeap.size, sizeof(Node), compare);
    while (minHeap.size > 0) {
        Node node = minHeap.nodes[0];
        minHeap.size--;
        for (int i = 0; i < M; i++) {
            if (edges[i][0] == node.vertex) {
                int neighbor = edges[i][1];
                long long weight = edges[i][2];
                if (distances[neighbor] > node.distance + weight) {
                    distances[neighbor] = node.distance + weight;
                }
            }
        }
    }
    for (int i = 0; i < N; i++) {
        if (distances[i] == INF) {
            printf("-1 ");
        } else {
            printf("%lld ", distances[i]);
        }
    }
    printf("\n");
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **edges = (int **)calloc(M, sizeof(int *));
        for (int i = 0; i < M; i++) {
            edges[i] = (int *)calloc(3, sizeof(int));
            scanf("%d %d %d", &edges[i][0], &edges[i][1], &edges[i][2]);
        }
        dijkstra(N, M, edges);
    }
    return 0;
}

