#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;
const int N = 200001;
const long long INF = 1000000000000000000LL;
void dijkstra(int N, int M, vector<vector<int>> &edges) {
    vector<long long> distances(N, INF);
    distances[0] = 0;
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> minHeap;
    minHeap.push({0, 0});
    while (!minHeap.empty()) {
        pair<long long, int> node = minHeap.top();
        minHeap.pop();
        for (int i = 0; i < M; i++) {
            if (edges[i][0] == node.second) {
                int neighbor = edges[i][1];
                long long weight = edges[i][2];
                if (distances[neighbor] > node.first + weight) {
                    distances[neighbor] = node.first + weight;
                    minHeap.push({distances[neighbor], neighbor});
                }
            }
        }
    }
    for (int i = 0; i < N; i++) {
        if (distances[i] == INF) {
            cout << -1 << " ";
        } else {
            cout << distances[i] << " ";
        }
    }
    cout << endl;
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N, M;
        cin >> N >> M;
        vector<vector<int>> edges(M, vector<int>(3));
        for (int i = 0; i < M; i++) {
            cin >> edges[i][0] >> edges[i][1] >> edges[i][2];
        }
        dijkstra(N, M, edges);
    }
    return 0;
}

