import java.util.*;
public class Main {
    static final int N = 200001;
    static final long INF = 1000000000000000000L;
    static long[] d = new long[N];
    static List<int[]>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            for (int i = 0; i < N; i++) {
                adj[i] = new ArrayList<>();
            }
            for (int i = 0; i < M; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                int w = sc.nextInt();
                adj[u].add(new int[] {v, w});
                adj[v].add(new int[] {u, w});
            }
            dijkstra(N, M);
        }
    }
    public static void dijkstra(int N, int M) {
        for (int i = 0; i < N; i++) {
            d[i] = INF;
        }
        d[0] = 0;
        PriorityQueue<int[]> minHeap = new PriorityQueue<>((a, b) -> a[1] - b[1]);
        minHeap.add(new int[] {0, 0});
        while (!minHeap.isEmpty()) {
            int[] node = minHeap.poll();
            for (int[] neighbor : adj[node[0]]) {
                if (d[neighbor[0]] > d[node[0]] + neighbor[1]) {
                    d[neighbor[0]] = d[node[0]] + neighbor[1];
                    minHeap.add(new int[] {neighbor[0], (int) d[neighbor[0]]});
                }
            }
        }
        for (int i = 0; i < N; i++) {
            if (d[i] == INF) {
                System.out.print(-1 + " ");
            } else {
                System.out.print(d[i] + " ");
            }
        }
        System.out.println();
    }
}

